"use client";

import { useCallback, useEffect, useState } from "react";

interface CompleteUser {
  id: number;
  userid: string;
  divisi: string;
  nama: string;
  email: string;
  nik: string;
  telepon: string;
  username: string | null;
  nip: string | null;
  status_ppat: string | null;
  verifiedstatus: string;
}

const PAGE_SIZE = 20;

export default function AdminDataUserCompletePage() {
  const [users, setUsers] = useState<CompleteUser[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState(1);

  const loadComplete = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/users/complete", { credentials: "include" });
      if (!res.ok) throw new Error("Gagal memuat data pengguna");
      const data = await res.json();
      setUsers(Array.isArray(data) ? data : []);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Terjadi kesalahan");
      setUsers([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadComplete();
  }, [loadComplete]);

  const totalPages = Math.max(1, Math.ceil(users.length / PAGE_SIZE));
  const startIdx = (page - 1) * PAGE_SIZE;
  const pageUsers = users.slice(startIdx, startIdx + PAGE_SIZE);

  return (
    <div>
      <h1 style={{ color: "#fff", margin: "0 0 0.5rem" }}>
        Data User (Complete)
      </h1>
      <p style={{ color: "rgba(255,255,255,0.7)", margin: "0 0 1rem" }}>
        User yang sudah terverifikasi dan memiliki UserID
      </p>

      {error && (
        <p style={{ color: "#f87171", marginBottom: "1rem" }}>{error}</p>
      )}

      {loading ? (
        <p style={{ color: "rgba(255,255,255,0.7)" }}>Memuat...</p>
      ) : (
        <>
          <div
            style={{
              overflowX: "auto",
              background: "#1b263b",
              borderRadius: 8,
              border: "1px solid rgba(65,90,119,0.3)",
            }}
          >
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ borderBottom: "1px solid rgba(65,90,119,0.5)" }}>
                  <th style={thStyle}>UserID</th>
                  <th style={thStyle}>Divisi</th>
                  <th style={thStyle}>Nama</th>
                  <th style={thStyle}>Email</th>
                  <th style={thStyle}>NIK</th>
                  <th style={thStyle}>Telepon</th>
                  <th style={thStyle}>Username</th>
                  <th style={thStyle}>Status</th>
                </tr>
              </thead>
              <tbody>
                {pageUsers.map((u) => (
                  <tr
                    key={u.id}
                    style={{ borderBottom: "1px solid rgba(65,90,119,0.2)" }}
                  >
                    <td style={tdStyle}>{u.userid}</td>
                    <td style={tdStyle}>{u.divisi}</td>
                    <td style={tdStyle}>{u.nama}</td>
                    <td style={tdStyle}>{u.email}</td>
                    <td style={tdStyle}>{u.nik}</td>
                    <td style={tdStyle}>{u.telepon}</td>
                    <td style={tdStyle}>{u.username ?? "—"}</td>
                    <td style={tdStyle}>{u.verifiedstatus}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {totalPages > 1 && (
            <div
              style={{
                display: "flex",
                gap: 6,
                justifyContent: "center",
                marginTop: 12,
              }}
            >
              <button
                type="button"
                disabled={page === 1}
                onClick={() => setPage(1)}
                style={pageBtnStyle}
              >
                «
              </button>
              <button
                type="button"
                disabled={page === 1}
                onClick={() => setPage((p) => p - 1)}
                style={pageBtnStyle}
              >
                ‹
              </button>
              {Array.from({ length: totalPages }, (_, i) => i + 1)
                .filter((p) => Math.abs(p - page) <= 2)
                .map((p) => (
                  <button
                    key={p}
                    type="button"
                    onClick={() => setPage(p)}
                    style={{
                      ...pageBtnStyle,
                      ...(p === page
                        ? { background: "#0ea5e9", color: "#fff" }
                        : {}),
                    }}
                  >
                    {p}
                  </button>
                ))}
              <button
                type="button"
                disabled={page === totalPages}
                onClick={() => setPage(totalPages)}
                style={pageBtnStyle}
              >
                »
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

const thStyle: React.CSSProperties = {
  padding: "10px 12px",
  textAlign: "left",
  color: "rgba(255,255,255,0.9)",
  fontWeight: 600,
};
const tdStyle: React.CSSProperties = {
  padding: "10px 12px",
  color: "rgba(255,255,255,0.85)",
};
const pageBtnStyle: React.CSSProperties = {
  minWidth: 34,
  height: 34,
  borderRadius: 8,
  border: "1px solid rgba(65,90,119,0.5)",
  background: "#1b263b",
  color: "#fff",
  cursor: "pointer",
};
